 70→// Animated number hook for smooth credit transitions
 71→const useAnimatedNumber = (value: number, duration = 600) => {
 72→  const [display, setDisplay] = useState(value);
 73→  const prevValue = useRef(value);
 74→  useEffect(() => {
 75→    if (prevValue.current === value) return;
 76→    const start = prevValue.current;
 77→    const diff = value - start;
 78→    const startTime = performance.now();
 79→    const animate = (now: number) => {
 80→      const progress = Math.min((now - startTime) / duration, 1);
 81→      const eased = 1 - Math.pow(1 - progress, 3);
 82→      setDisplay(Math.round(start + diff * eased));
 83→      if (progress < 1) requestAnimationFrame(animate);
 84→    };
 85→    requestAnimationFrame(animate);
 86→    prevValue.current = value;
 87→  }, [value, duration]);
 88→  return display;
 89→};
 90→
 91→const PLAN_LIMITS = {
 92→  free: 1,
 93→  pro: 3,
 94→  enterprise: 1000
 95→};
 96→
 97→type ViewName = 'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking' | 'mission-orders' | 'blog-optimizer' | 'ai-response-layer' | 'llms-txt' | 'answer-first-audit' | 'ai-citation-simulator' | 'eeat-builder' | 'ai-monitoring' | 'integrations' | 'api-developer' | 'citation-dashboard' | 'tracked-queries' | 'citation-detail' | 'benchmark' | 'v3-alerts' | 'alert-settings' | 'monthly-report' | 'calibration';
 98→
 99→const App: React.FC = () => {
100→  return (
101→    <I18nProvider>
102→      <AppContent />
103→    </I18nProvider>
104→  );
105→};
106→
107→const AppContent: React.FC = () => {
108→  const { t } = useTranslation();
109→
110→  // ── Toast system ──
111→  const [toasts, setToasts] = useState<Toast[]>([]);
112→  const showToast = useCallback((type: Toast['type'], message: string) => {
113→    const id = Date.now().toString();
114→    setToasts(prev => [...prev, { id, type, message }]);
115→    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3500);
116→  }, []);
117→  const removeToast = useCallback((id: string) => {
118→    setToasts(prev => prev.filter(t => t.id !== id));
119→  }, []);
120→
121→  // ── 2-level routing: section + page ──
122→  const [currentView, setCurrentView] = useState<ViewName>('home');
123→  const [activeSection, setActiveSection] = useState<Section>('dashboard');
124→  const [viewHistory, setViewHistory] = useState<string[]>([]);
125→  const [refreshKey, setRefreshKey] = useState(0);
126→  const [pageKey, setPageKey] = useState(0);
127→
128→  // ── Data state ──
129→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
130→  const [history, setHistory] = useState<AnalysisResult[]>([]);
131→
132→  useEffect(() => {
133→    const loadedHistory = db.getAll();
134→    setHistory(loadedHistory);
135→  }, []);
136→
137→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]);
138→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
139→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
140→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
141→
142→  const [megaStatus, setMegaStatus] = useState<MegaGenerationStatus>('idle');
143→  const [isAnalyzing, setIsAnalyzing] = useState(false);
144→  const [resultsTab, setResultsTab] = useState<'overview' | 'details' | 'archives' | 'recommendations'>('overview');
145→  const [publisherRequestData, setPublisherRequestData] = useState<{ topic: string, url: string, brief: string } | null>(null);
146→  const [initialRechargePackId, setInitialRechargePackId] = useState<number | null>(null);
147→  const [initialAccountTab, setInitialAccountTab] = useState<'profile' | 'subscription' | 'billing'>('profile');
148→
149→  // ── Layout state ──
150→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
151→  const [lowCreditsDismissed, setLowCreditsDismissed] = useState(false);
152→
153→  // ── Command Palette & Shortcuts ──
154→  const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);
155→  const [isShortcutsOpen, setIsShortcutsOpen] = useState(false);
156→  useEffect(() => {
157→    const handleKeyDown = (e: KeyboardEvent) => {
158→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
159→        e.preventDefault();
160→        setIsCommandPaletteOpen(prev => !prev);
161→      }
162→      if (e.key === 'Escape') {
163→        setIsCommandPaletteOpen(false);
164→        setIsShortcutsOpen(false);
165→      }
166→      if (e.key === '?' && !(e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement)) {
167→        setIsShortcutsOpen(prev => !prev);
168→      }
169→    };
170→    document.addEventListener('keydown', handleKeyDown);
171→    return () => document.removeEventListener('keydown', handleKeyDown);
172→  }, []);
173→
174→  // ── Welcome Onboarding ──
175→  const [showOnboarding, setShowOnboarding] = useState(false);
176→  const [user, setUser] = useState<User | null>(null);
177→  const animatedCredits = useAnimatedNumber(user?.credits ?? 0);
178→  const [showCelebration, setShowCelebration] = useState(false);
179→
180→  useEffect(() => {
181→    if (user && !localStorage.getItem('citedby_onboarded')) {
182→      setShowOnboarding(true);
183→    }
184→  }, [user]);
185→
186→  // ── Monthly project count ──
187→  const monthlyProjectCount = useMemo(() => {
188→    if (history.length === 0) return 0;
189→    const now = new Date();
190→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
191→    const projectCreationDates = new Map<string, Date>();
192→    history.forEach(h => {
193→      let hostname;
194→      try { hostname = new URL(h.url).hostname; } catch { hostname = h.url; }
195→      const analysisDate = new Date(h.timestamp);
196→      if (!projectCreationDates.has(hostname)) {
197→        projectCreationDates.set(hostname, analysisDate);
198→      } else {
199→        if (analysisDate < projectCreationDates.get(hostname)!) {
200→          projectCreationDates.set(hostname, analysisDate);
201→        }
202→      }
203→    });
204→    let count = 0;
205→    projectCreationDates.forEach((creationDate) => {
206→      if (creationDate >= billingCycleStart) count++;
207→    });
208→    return count;
209→  }, [history]);
210→
211→  // ── Action plan status ──
212→  const actionPlanStatus = useMemo(() => {
213→    if (history.length === 0) return { complete: false, completed: 0, total: 0 };
214→    const latest = history[history.length - 1];
215→    const total = latest.recommendations.length;
216→    const completed = latest.recommendations.filter(rec =>
217→      latest.generatedSolutions?.[rec.id]
218→    ).length;
219→    return { complete: total > 0 && completed === total, completed, total };
220→  }, [history]);
221→
222→  // ── Navigation ──
223→  const navigateTo = useCallback((view: ViewName | string) => {
224→    const v = view as ViewName;
225→    if (v !== 'recharge') setInitialRechargePackId(null);
226→    if (v !== 'account') setInitialAccountTab('profile');
227→    setViewHistory(prev => [...prev, currentView]);
228→    setCurrentView(v);
229→    // Auto-sync section from page
230→    const section = getSectionForPage(v);
231→    setActiveSection(section);
232→    setRefreshKey(prev => prev + 1);
233→    setPageKey(prev => prev + 1);
234→    window.scrollTo({ top: 0, behavior: 'smooth' });
235→  }, [currentView]);
236→
237→  const goBack = useCallback(() => {
238→    if (viewHistory.length > 0) {
239→      const newHistory = [...viewHistory];
240→      const prevView = newHistory.pop();
241→      setViewHistory(newHistory);
242→      if (prevView) {
243→        const v = prevView as ViewName;
244→        setCurrentView(v);
245→        setActiveSection(getSectionForPage(v));
246→        setRefreshKey(prev => prev + 1);
247→        window.scrollTo({ top: 0, behavior: 'smooth' });
248→      }
249→    } else {
250→      setCurrentView('home');
251→      setActiveSection('dashboard');
252→      setRefreshKey(prev => prev + 1);
253→    }
254→  }, [viewHistory]);
255→
256→  const handleSectionChange = useCallback((section: Section) => {
257→    setActiveSection(section);
258→    // Navigate to default page of each section
259→    const defaults: Record<Section, ViewName> = {
260→      dashboard: 'dashboard',
261→      analyse: 'analyze',
262→      citations: 'citation-dashboard',
263→      outils: 'generative-tools',
264→      marketplace: 'directory',
265→      parametres: 'account',
266→    };
267→    const target = defaults[section];
268→    setViewHistory(prev => [...prev, currentView]);
269→    setCurrentView(target);
270→    setRefreshKey(prev => prev + 1);
271→    setPageKey(prev => prev + 1);
272→    window.scrollTo({ top: 0, behavior: 'smooth' });
273→  }, [currentView]);
274→
275→  const handleDirectRecharge = (packId: number) => {
276→    setInitialRechargePackId(packId);
277→    navigateTo('recharge');
278→  };
279→
280→  // ── Analysis handler ──
281→  const handleAnalyze = async (url: string) => {
282→    if (user) {
283→      const limit = PLAN_LIMITS[user.plan] || 1;
284→      let hostname = url;
285→      try { hostname = new URL(url).hostname; } catch { /* keep raw */ }
286→      const isExistingProject = history.some(h => {
287→        try { return new URL(h.url).hostname === hostname; }
288→        catch { return false; }
289→      });
290→      if (!isExistingProject && monthlyProjectCount >= limit) {
291→        alert(`Limite de nouveaux projets atteinte pour ce mois (${monthlyProjectCount}/${limit}). Passez au plan superieur pour ajouter plus de projets.`);
292→        setInitialAccountTab('subscription');
293→        navigateTo('account');
294→        return;
295→      }
296→    }
297→
298→    setIsAnalyzing(true);
299→    try {
300→      const result = await analyzeUrl(url);
301→      setAnalysisData(result);
302→      const updatedHistory = db.add(result);
303→      setHistory(updatedHistory);
304→
305→      if (history.length === 0) {
306→        setShowCelebration(true);
307→        setTimeout(() => setShowCelebration(false), 3000);
308→      }
309→
310→      showToast('success', 'Audit termine avec succes !');
311→
312→      // Pre-generation en arriere-plan
313→      setMegaStatus('generating');
314→      megaGenerate(url).then(cache => {
315→        if (cache) {
316→          const preGenerated = { status: 'completed' as const, generatedAt: new Date().toISOString(), ...cache };
317→          setHistory(prev => {
318→            if (prev.length === 0) return prev;
319→            const updated = { ...prev[0], preGenerated };
320→            db.update(0, updated);
321→            return [updated, ...prev.slice(1)];
322→          });
323→          setAnalysisData(prev => prev ? { ...prev, preGenerated } : prev);
324→          setMegaStatus('completed');
325→        } else {
326→          setMegaStatus('failed');
327→        }
328→      }).catch(() => setMegaStatus('failed'));
329→
330→      // Solution mega-generation (Generate All, Reveal on Credit)
331→      const auditId = result.timestamp;
332→      if (!hasVault(auditId)) {
333→        const failedCriteria = result.recommendations.map(rec => ({
334→          id: rec.id,
335→          name: rec.title,
336→          category: rec.category,
337→          maxPoints: rec.priority === 'critical' ? 5 : rec.priority === 'high' ? 4 : rec.priority === 'medium' ? 3 : 1,
338→        }));
339→        let hostname = url;
340→        try { hostname = new URL(url).hostname; } catch { /* keep raw */ }
341→        generateAllSolutions(
342→          url, hostname,
343→          result.recommendations.map(r => r.title).join('. '),
344→          failedCriteria, [], hostname, 'fr'
345→        ).then(megaResult => {
346→          storeInVault(auditId, megaResult);
347→          console.log('[SolutionMegaGen] Solutions pre-generees et stockees:', megaResult.solutionsCount);
348→        }).catch(err => {
349→          console.error('[SolutionMegaGen] Erreur:', err);
350→        });
351→      }
352→
353→      setResultsTab('details');
354→      navigateTo('projects');
355→    } catch (error) {
356→      console.error("Analysis failed", error);
357→      alert("Erreur lors de l'analyse. Veuillez reessayer.");
358→    } finally {
359→      setIsAnalyzing(false);
360→    }
361→  };
362→
363→  // ── View analysis handler ──
364→  const handleViewAnalysis = (result: AnalysisResult, tab: 'overview' | 'details' | 'recommendations' | 'preview' = 'overview') => {
365→    setAnalysisData(result);
366→    setResultsTab(tab as typeof resultsTab);
367→    navigateTo('projects');
368→  };
369→
370→  const handleViewDirectoryEntity = (result: AnalysisResult) => {
371→    setAnalysisData(result);
372→    navigateTo('directory-entity');
373→  };
374→
375→  const handleUpdateAnalysis = (index: number, updatedData: Partial<AnalysisResult>) => {
376→    const updatedHistory = db.update(index, updatedData);
377→    setHistory(updatedHistory);
378→  };
379→
380→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
381→    const timestamp = new Date().toISOString();
382→    const solutionWithMeta = { ...solution, timestamp };
383→    setAnalysisData(prev => {
384→      if (!prev || prev.timestamp !== analysisId) return prev;
385→      return {
386→        ...prev,
387→        generatedSolutions: {
388→          ...(prev.generatedSolutions || {}),
389→          [recommendationId]: solutionWithMeta
390→        }
391→      };
392→    });
393→    setHistory(prevHistory => {
394→      const index = prevHistory.findIndex(item => item.timestamp === analysisId);
395→      if (index !== -1) {
396→        const updatedItem = {
397→          ...prevHistory[index],
398→          generatedSolutions: {
399→            ...(prevHistory[index].generatedSolutions || {}),
400→            [recommendationId]: solutionWithMeta
401→          }
402→        };
403→        const newHistory = [...prevHistory];
404→        newHistory[index] = updatedItem;
405→        db.update(index, updatedItem);
406→        return newHistory;
407→      }
408→      return prevHistory;
409→    });
410→  }, []);
411→
412→  const handleAddToSmcLibrary = (item: SMCContent) => setSmcLibrary(prev => [item, ...prev]);
413→  const handleAddToTruthLibrary = (item: SMCContent) => setTruthLibrary(prev => [item, ...prev]);
414→  const handleAddToSchemaLibrary = (item: SMCContent) => setSchemaLibrary(prev => [item, ...prev]);
415→  const handleAddToRobotsLibrary = (item: SMCContent) => setRobotsLibrary(prev => [item, ...prev]);
416→
417→  const handleNavigateToPublisher = (data: { topic: string, url: string, brief: string }) => {
418→    setPublisherRequestData(data);
419→    navigateTo('publisher-request');
420→  };
421→
422→  const handleNavigateToDirectory = () => navigateTo('directory');
423→
424→  const handleDeductCredits = (amount: number): boolean => {
425→    if (!user) {
426→      if (confirm("Vous devez etre connecte pour effectuer cette action. Se connecter maintenant ?")) {
427→        navigateTo('login');
428→      }
429→      return false;
430→    }
431→    if (user.credits < amount) {
432→      alert(`Solde GTO Gas insuffisant pour generer cette solution.\n\nIl vous manque ${amount - user.credits} credits.\n\nRedirection vers la station de recharge...`);
433→      navigateTo('recharge');
434→      return false;
435→    }
436→    setUser(prev => prev ? { ...prev, credits: prev.credits - amount } : null);
437→    return true;
438→  };
439→
440→  const handleRecharge = (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => {
441→    if (!user) return;
442→    setUser({ ...user, credits: user.credits + amount, plan: planLevel });
443→  };
444→
445→  const handleUpgradePlan = (newPlan: 'free' | 'pro' | 'enterprise') => {
446→    if (!user) return;
447→    setUser({ ...user, plan: newPlan });
448→  };
449→
450→  const handleLogin = (loggedInUser: User) => {
451→    setUser(loggedInUser);
452→    setViewHistory(['home']);
453→    setCurrentView('analyze');
454→    setActiveSection('analyse');
455→    setRefreshKey(prev => prev + 1);
456→  };
457→
458→  const handleLogout = () => {
459→    setUser(null);
460→    setCurrentView('home');
461→    setActiveSection('dashboard');
462→    setViewHistory([]);
463→    setRefreshKey(prev => prev + 1);
464→  };
465→
466→  // ── Render ──
467→  const isPublicPage = ['home', 'login'].includes(currentView);
468→
469→  return (
470→    <ToastContext.Provider value={{ showToast }}>
471→      {/* Toast Notifications */}
472→      <ToastContainer toasts={toasts} onRemove={removeToast} />
473→
474→      {/* Celebration overlay */}
475→      {showCelebration && (
476→        <div className="fixed inset-0 z-[200] pointer-events-none flex items-center justify-center">
477→          <div className="text-center animate-in fade-in zoom-in duration-500">
478→            <div className="text-6xl mb-4 animate-bounce">&#127881;</div>
479→            <div className="bg-[#13131d]/90 backdrop-blur-xl border border-purple-500/30 rounded-2xl px-8 py-5 shadow-2xl shadow-purple-900/30">
480→              <h3 className="text-xl font-bold text-white mb-1">Premier audit reussi !</h3>
481→              <p className="text-sm text-purple-300">Votre parcours AEO commence maintenant</p>
482→            </div>
483→          </div>
484→        </div>
485→      )}
486→
487→      {/* Onboarding */}
488→      <OnboardingModal
489→        show={showOnboarding}
490→        onClose={() => setShowOnboarding(false)}
491→        onNavigate={(view: string) => navigateTo(view as ViewName)}
492→      />
493→
494→      {/* Command Palette */}
495→      {user && isCommandPaletteOpen && (
496→        <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={() => setIsCommandPaletteOpen(false)}>
497→          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
498→          <CommandPalettePanel
499→            onClose={() => setIsCommandPaletteOpen(false)}
500→            onNavigate={(view: string) => { navigateTo(view as ViewName); setIsCommandPaletteOpen(false); }}
501→          />
502→        </div>
503→      )}
504→
505→      {/* Shortcuts Modal */}
506→      <ShortcutsModal isOpen={isShortcutsOpen} onClose={() => setIsShortcutsOpen(false)} />
507→
508→      {/* Public pages (Home, Login) — no shell */}
509→      {isPublicPage && !user && (
510→        <div className="min-h-screen bg-[#0F172A]">
511→          {currentView === 'home' && (
512→            <Home
513→              key={`home-${refreshKey}`}
514→              onNavigate={(view) => navigateTo(view)}
515→              user={user}
516→              onDirectRecharge={handleDirectRecharge}
517→            />
518→          )}
519→          {currentView === 'login' && (
520→            <Login key={`login-${refreshKey}`} onLogin={handleLogin} onBack={goBack} />
521→          )}
522→        </div>
523→      )}
524→
525→      {/* Authenticated layout with AppShell */}
526→      {(user || !isPublicPage) && !(isPublicPage && !user) && (
527→        <AppShell
528→          user={user}
529→          activeSection={activeSection}
530→          activePage={currentView}
531→          onSectionChange={handleSectionChange}
532→          onNavigate={(v) => navigateTo(v as ViewName)}
533→          animatedCredits={animatedCredits}
534→          onOpenCommandPalette={() => setIsCommandPaletteOpen(true)}
535→          onLogout={handleLogout}
536→          isSidebarCollapsed={isSidebarCollapsed}
537→          onToggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
