12→// ================================================================
13→// URL PARSING HELPERS
14→// ================================================================
15→
16→const parseUrl = (urlStr: string) => {
17→  let hostname = urlStr;
18→  let protocol = 'https';
19→  let origin = `https://${urlStr}`;
20→
21→  try {
22→    const urlObj = new URL(urlStr.startsWith('http') ? urlStr : `https://${urlStr}`);
23→    hostname = urlObj.hostname;
24→    protocol = urlObj.protocol.replace(':', '');
25→    origin = urlObj.origin;
26→  } catch (e) {
27→    // Fallback
28→  }
29→
30→  const cleanName = hostname.replace('www.', '').split('.')[0];
31→  const entityName = cleanName.charAt(0).toUpperCase() + cleanName.slice(1);
32→
33→  // Simple platform detection
34→  const lowerUrl = urlStr.toLowerCase();
35→  let platform = 'Site General';
36→  if (lowerUrl.includes('shopify') || lowerUrl.includes('store') || lowerUrl.includes('shop')) {
37→    platform = 'Shopify / E-commerce';
38→  } else if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
39→    platform = 'WordPress';
40→  } else if (lowerUrl.includes('app.') || lowerUrl.includes('dashboard') || lowerUrl.includes('portal')) {
41→    platform = 'SaaS / Web App';
42→  }
43→
44→  return { hostname, protocol, origin, entityName, platform };
45→};
