 1→import { createServerClient, type CookieOptions } from '@supabase/ssr'
 2→import { NextResponse, type NextRequest } from 'next/server'
 3→
 4→export async function updateSession(request: NextRequest) {
 5→  let response = NextResponse.next({
 6→    request: {
 7→      headers: request.headers,
 8→    },
 9→  })
10→
11→  const supabase = createServerClient(
12→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
13→    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
14→    {
15→      cookies: {
16→        get(name: string) {
17→          return request.cookies.get(name)?.value
18→        },
19→        set(name: string, value: string, options: CookieOptions) {
20→          request.cookies.set({
21→            name,
22→            value,
23→            ...options,
24→          })
25→          response = NextResponse.next({
26→            request: {
27→              headers: request.headers,
28→            },
29→          })
30→          response.cookies.set({
31→            name,
32→            value,
33→            ...options,
34→          })
35→        },
36→        remove(name: string, options: CookieOptions) {
37→          request.cookies.set({
38→            name,
39→            value: '',
40→            ...options,
41→          })
42→          response = NextResponse.next({
43→            request: {
44→              headers: request.headers,
45→            },
46→          })
47→          response.cookies.set({
48→            name,
49→            value: '',
50→            ...options,
51→          })
52→        },
53→      },
54→    }
55→  )
56→
57→  const { data: { user } } = await supabase.auth.getUser()
58→
59→  // Protect /app routes
60→  if (request.nextUrl.pathname.startsWith('/app') && !user) {
61→    return NextResponse.redirect(new URL('/login', request.url))
62→  }
63→
64→  // Redirect logged in users away from auth pages
65→  if ((request.nextUrl.pathname === '/login' || request.nextUrl.pathname === '/register') && user) {
66→    return NextResponse.redirect(new URL('/app', request.url))
67→  }
68→
69→  return response
70→}

 1→import React, { useState, useEffect, useRef } from 'react';
 2→
 3→// Animated counter hook
 4→const useCountUp = (target: number, duration = 1200) => {
 5→  const [count, setCount] = useState(0);
 6→  const ref = useRef<HTMLDivElement>(null);
 7→  useEffect(() => {
 8→    const observer = new IntersectionObserver(([entry]) => {
 9→      if (entry.isIntersecting) {
10→        const startTime = performance.now();
11→        const step = (now: number) => {
12→          const progress = Math.min((now - startTime) / duration, 1);
13→          const eased = 1 - Math.pow(1 - progress, 3);
14→          setCount(Math.round(eased * target));
15→          if (progress < 1) requestAnimationFrame(step);
16→        };
17→        requestAnimationFrame(step);
18→        observer.disconnect();
19→      }
20→    }, { threshold: 0.3 });
21→    if (ref.current) observer.observe(ref.current);
22→    return () => observer.disconnect();
23→  }, [target, duration]);
24→  return { count, ref };
25→};
