## 2. State Management Migration

### Problem

`C:/Users/User/citedby-ai/App.tsx` (lines 107-438) manages ALL state centrally and passes it as props to all 36 pages. Every page receives some combination of: `user`, `onBack`, `onNavigate`, `onDeductCredits`, `showToast`, `history`, `analysisData`, `onSaveSolution`, plus various library arrays.

### Solution: AppProvider Context

Create `C:/Users/User/citedby-ai/lib/app-context.tsx` with a React Context that holds all shared state. This is a `'use client'` component.

**State to include:**

```typescript
interface AppContextValue {
  // User
  user: User | null;
  setUser: (user: User | null) => void;
  animatedCredits: number;

  // Data
  history: AnalysisResult[];
  setHistory: React.Dispatch<React.SetStateAction<AnalysisResult[]>>;
  analysisData: AnalysisResult | null;
  setAnalysisData: React.Dispatch<React.SetStateAction<AnalysisResult | null>>;

  // Libraries
  smcLibrary: SMCContent[];
  truthLibrary: SMCContent[];
  schemaLibrary: SMCContent[];
  robotsLibrary: SMCContent[];
  addToSmcLibrary: (item: SMCContent) => void;
  addToTruthLibrary: (item: SMCContent) => void;
  addToSchemaLibrary: (item: SMCContent) => void;
  addToRobotsLibrary: (item: SMCContent) => void;

  // Status
  megaStatus: MegaGenerationStatus;
  setMegaStatus: React.Dispatch<React.SetStateAction<MegaGenerationStatus>>;
  isAnalyzing: boolean;

  // Actions
  handleAnalyze: (url: string) => Promise<void>;
  handleDeductCredits: (amount: number) => boolean;
  handleRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  handleSaveSolution: (analysisId: string, recommendationId: string, solution: GeneratedSolution) => void;
  handleLogin: (user: User) => void;
  handleLogout: () => void;

  // Navigation helpers
  navigateTo: (viewName: string) => void;
  goBack: () => void;

  // Computed
  monthlyProjectCount: number;
  maxProjects: number;
  actionPlanStatus: { complete: boolean; completed: number; total: number };

  // Page-specific state (for cross-page params)
  resultsTab: string;
  setResultsTab: (tab: string) => void;
  publisherRequestData: { topic: string; url: string; brief: string } | null;
  setPublisherRequestData: React.Dispatch<React.SetStateAction<any>>;
  initialRechargePackId: number | null;
  setInitialRechargePackId: React.Dispatch<React.SetStateAction<number | null>>;
  initialAccountTab: 'profile' | 'subscription' | 'billing';
  setInitialAccountTab: React.Dispatch<React.SetStateAction<'profile' | 'subscription' | 'billing'>>;
