### API Route Pattern

Each route follows this pattern:

```typescript
// app/api/ai/smc/route.ts
import { NextResponse } from 'next/server';
import { smcService } from '@/services/smc';

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { action, ...params } = body;

    let result;
    switch (action) {
      case 'fiche':
        result = await smcService.generateFiche(params.productName, params.features);
        break;
      case 'faq':
        result = await smcService.generateFaq(params.productName, params.questions);
        break;
      case 'brief':
        result = await smcService.generateBrief(params.topic, params.keywords);
        break;
      case 'article':
        result = await smcService.generateArticle(params.topic, params.outline);
        break;
      default:
        return NextResponse.json({ error: 'Unknown action' }, { status: 400 });
    }

    return NextResponse.json({ result });
  } catch (error) {
    console.error('[API] SMC generation error:', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}
```

### Client-Side Service Wrappers

Create `C:/Users/User/citedby-ai/lib/api-client.ts` that provides the same interface as the original services but calls `fetch()`:

```typescript
export const smcApi = {
  generateFiche: async (productName: string, features: string): Promise<string> => {
    const res = await fetch('/api/ai/smc', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'fiche', productName, features }),
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error);
    return data.result;
  },
  // ... other methods
};
```

### Environment Variable Changes

The services currently read `process.env.API_KEY`. For Next.js server-side API routes, rename the env var to `GEMINI_API_KEY` (without NEXT_PUBLIC_ prefix so it stays server-only). Update all `getApiKey()` functions in services:

```typescript
const getApiKey = () => {
  return process.env.GEMINI_API_KEY || process.env.API_KEY || null;
};
```

The `.env.local` file at `C:/Users/User/citedby-ai/.env.local` should have:
```
GEMINI_API_KEY=your_key_here
```

### V3 Citation Services Special Case

The V3 services (`C:/Users/User/citedby-ai/services/v3/citation-api-client.ts`) use `import.meta.env.VITE_OPENAI_API_KEY`, `import.meta.env.VITE_PERPLEXITY_API_KEY`, and `import.meta.env.VITE_GEMINI_API_KEY`. These are Vite-specific and must be changed to `process.env.OPENAI_API_KEY`, `process.env.PERPLEXITY_API_KEY`, and `process.env.GEMINI_API_KEY` when used server-side.

